from agno import Agent
from vex import verify

class ContextTracker:
    def __init__(self):
        self.context_hashes = {}

    def verify_context(self, agent_outputs):
        current_hash = hash(str(agent_outputs['shared_context']))
        agent_id = agent_outputs['agent_id']
        if agent_id in self.context_hashes:
            return abs(current_hash - self.context_hashes[agent_id]) < 1000
        self.context_hashes[agent_id] = current_hash
        return True

tracker = ContextTracker()

@verify(tracker.verify_context)
def agent_with_context(inputs):
    agent = Agent(name='coordinator')
    return agent.run(inputs)

