from agno.tools import Tool

class Blackboard:
    def __init__(self):
        self.data = {}

    def read(self, key):
        return self.data.get(key)

    def write(self, key, value):
        # Validate before writing
        if key == 'price' and isinstance(value, str):
            value = float(value.replace('K', '000'))
        self.data[key] = value
        return value

