from agno import Agent, Team

class SequentialTeam(Team):
    def run(self, inputs):
        results = {}
        for agent in self.agents:
            # Pass previous results as context
            context = {**inputs, **results}
            results[agent.name] = agent.run(context)
            # Validate handoff
            if not self.validate_handoff(results):
                raise ValueError('Handoff validation failed')
        return results

    def validate_handoff(self, results):
        return 'price' in results.get('extractor', {})
